/**
 * Main Page Builder Interface
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import React, { useState, useCallback, useEffect } from 'react';
import { DndContext, DragEndEvent, DragOverlay, DragStartEvent } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable';
import { Canvas } from './Canvas';
import { SectionLibrary } from './SectionLibrary';
import { PropertyPanel } from './PropertyPanel';
import { Toolbar } from './Toolbar';
import { PreviewModes } from './PreviewModes';
import { InlineCSSEditor } from '@/components/ui/InlineCSSEditor';
import { MediaBrowser } from './MediaBrowser';
import { PageJSONEditor } from './PageJSONEditor';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { SECTION_TEMPLATES } from '@/lib/page-builder/section-registry';

interface PageBuilderProps {
  pageId: string;
  initialSections?: SectionConfig[];
  onSave?: (sections: SectionConfig[]) => Promise<void>;
  adminMode?: boolean;
  pageStatus?: string;
}

export function PageBuilder({ pageId, initialSections = [], onSave, adminMode = false, pageStatus }: PageBuilderProps) {
  const [sections, setSections] = useState<SectionConfig[]>(Array.isArray(initialSections) ? initialSections : []);
  const [selectedSectionId, setSelectedSectionId] = useState<string | null>(null);
  const [previewMode, setPreviewMode] = useState<'desktop' | 'tablet' | 'mobile'>('desktop');
  const [isPreviewMode, setIsPreviewMode] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [draggedSection, setDraggedSection] = useState<SectionConfig | null>(null);
  const [isSectionLibraryVisible, setIsSectionLibraryVisible] = useState(true);
  const [cssEditorSection, setCssEditorSection] = useState<{
    sectionId: string;
    sectionType: string;
    sectionOrder: number;
  } | null>(null);
  const [globalCSSEditor, setGlobalCSSEditor] = useState(false);
  const [pageCSSEditor, setPageCSSEditor] = useState<{
    pageId: string;
    pageTitle: string;
  } | null>(null);
  const [mediaBrowser, setMediaBrowser] = useState<{
    isOpen: boolean;
    onSelect: (url: string) => void;
    acceptTypes?: string[];
  }>({ isOpen: false, onSelect: () => {}, acceptTypes: ['image/*', 'video/*'] });
  const [isJSONEditorOpen, setIsJSONEditorOpen] = useState(false);

  const selectedSection = Array.isArray(sections) ? sections.find(s => s.id === selectedSectionId) : null;

  // Listen for CSS editor and media browser events
  useEffect(() => {
    const handleOpenCSSEditor = (event: CustomEvent) => {
      const { sectionId, sectionType, sectionOrder } = event.detail;
      setCssEditorSection({ sectionId, sectionType, sectionOrder });
    };

    const handleOpenGlobalCSSEditor = () => {
      setGlobalCSSEditor(true);
    };

    const handleOpenPageCSSEditor = (event: CustomEvent) => {
      const { pageId, pageTitle } = event.detail;
      setPageCSSEditor({ pageId, pageTitle });
    };

    const handleOpenMediaBrowser = (event: CustomEvent) => {
      const { onSelect, acceptTypes } = event.detail;
      setMediaBrowser({ isOpen: true, onSelect, acceptTypes: acceptTypes || ['image/*', 'video/*'] });
    };

    window.addEventListener('openCSSEditor', handleOpenCSSEditor as EventListener);
    window.addEventListener('openGlobalCSSEditor', handleOpenGlobalCSSEditor);
    window.addEventListener('openPageCSSEditor', handleOpenPageCSSEditor as EventListener);
    window.addEventListener('openMediaBrowser', handleOpenMediaBrowser as EventListener);
    
    return () => {
      window.removeEventListener('openCSSEditor', handleOpenCSSEditor as EventListener);
      window.removeEventListener('openGlobalCSSEditor', handleOpenGlobalCSSEditor);
      window.removeEventListener('openPageCSSEditor', handleOpenPageCSSEditor as EventListener);
      window.removeEventListener('openMediaBrowser', handleOpenMediaBrowser as EventListener);
    };
  }, []);

  // Add new section from library
  const handleAddSection = useCallback((templateType: string) => {
    const template = SECTION_TEMPLATES.find(t => t.type === templateType);
    if (!template) return;

    const newSection: SectionConfig = {
      ...template.defaultData,
      id: `section-${Date.now()}`,
      order: sections.length,
    };

    setSections(prev => [...prev, newSection]);
    setSelectedSectionId(newSection.id);
  }, [sections.length]);

  // Update section configuration
  const handleUpdateSection = useCallback((sectionId: string, updates: Partial<SectionConfig>) => {
    setSections(prev => prev.map(section => 
      section.id === sectionId 
        ? { ...section, ...updates } as SectionConfig
        : section
    ));
  }, []);

  // Delete section
  const handleDeleteSection = useCallback((sectionId: string) => {
    setSections(prev => prev.filter(s => s.id !== sectionId));
    if (selectedSectionId === sectionId) {
      setSelectedSectionId(null);
    }
  }, [selectedSectionId]);

  // Duplicate section
  const handleDuplicateSection = useCallback((sectionId: string) => {
    const section = sections.find(s => s.id === sectionId);
    if (!section) return;

    const duplicatedSection: SectionConfig = {
      ...section,
      id: `section-${Date.now()}`,
      order: section.order + 1,
    };

    setSections(prev => {
      const newSections = [...prev];
      const insertIndex = newSections.findIndex(s => s.id === sectionId) + 1;
      newSections.splice(insertIndex, 0, duplicatedSection);
      
      // Update order for sections after the duplicated one
      return newSections.map((s, index) => ({ ...s, order: index }));
    });
  }, [sections]);

  // Handle drag start
  const handleDragStart = (event: DragStartEvent) => {
    const { active } = event;
    const section = sections.find(s => s.id === active.id);
    setDraggedSection(section || null);
  };

  // Handle drag end
  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    setDraggedSection(null);

    if (!over || active.id === over.id) return;

    setSections(prev => {
      const oldIndex = prev.findIndex(s => s.id === active.id);
      const newIndex = prev.findIndex(s => s.id === over.id);

      if (oldIndex === -1 || newIndex === -1) return prev;

      const newSections = [...prev];
      const [movedSection] = newSections.splice(oldIndex, 1);
      newSections.splice(newIndex, 0, movedSection);

      // Update order
      return newSections.map((section, index) => ({
        ...section,
        order: index,
      }));
    });
  };

  // Save page
  const handleSave = async () => {
    if (!onSave) return;
    
    setIsSaving(true);
    try {
      await onSave(sections);
    } catch (error) {
      console.error('Failed to save page:', error);
    } finally {
      setIsSaving(false);
    }
  };

  // Handle JSON Editor save
  const handleJSONSave = (newSections: SectionConfig[]) => {
    setSections(newSections);
    setSelectedSectionId(null);
  };

  return (
    <div className="h-screen w-full flex flex-col bg-gray-50 dark:bg-gray-900 overflow-x-hidden">
      {/* Toolbar */}
      <Toolbar
        onSave={handleSave}
        isSaving={isSaving}
        isPreviewMode={isPreviewMode}
        onTogglePreview={() => setIsPreviewMode(!isPreviewMode)}
        previewMode={previewMode}
        onPreviewModeChange={setPreviewMode}
        pageId={pageId}
        pageStatus={pageStatus}
        isSectionLibraryVisible={isSectionLibraryVisible}
        onToggleSectionLibrary={() => setIsSectionLibraryVisible(!isSectionLibraryVisible)}
        onOpenJSONEditor={() => setIsJSONEditorOpen(true)}
      />

      <div className="flex-1 flex overflow-hidden relative">
        {!isPreviewMode && (
          <>
            {/* Section Library - Hidden when section is selected on small screens */}
            {isSectionLibraryVisible && (
              <div className={`${
                selectedSectionId ? 'hidden lg:flex' : 'flex'
              } flex-shrink-0`}>
                <SectionLibrary onAddSection={handleAddSection} />
              </div>
            )}

            {/* Main Canvas */}
            <div className="flex-1 flex flex-col min-w-0">
              <PreviewModes 
                mode={previewMode} 
                onModeChange={setPreviewMode} 
              />
              
              <DndContext onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
                <SortableContext 
                  items={sections.map(s => s.id)} 
                  strategy={verticalListSortingStrategy}
                >
                  <Canvas
                    sections={sections}
                    selectedSectionId={selectedSectionId}
                    onSectionSelect={setSelectedSectionId}
                    onSectionDelete={handleDeleteSection}
                    onSectionDuplicate={handleDuplicateSection}
                    previewMode={previewMode}
                    adminMode={adminMode}
                  />
                </SortableContext>
                
                <DragOverlay>
                  {draggedSection && (
                    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg p-4 opacity-90">
                      <p className="font-medium">{draggedSection.type}</p>
                    </div>
                  )}
                </DragOverlay>
              </DndContext>
            </div>

            {/* Property Panel - Overlay on small screens, sidebar on large */}
            {selectedSection && (
              <div className="fixed lg:relative inset-y-0 right-0 z-50 lg:flex-shrink-0 transform transition-transform duration-300 ease-in-out">
                <PropertyPanel
                  section={selectedSection}
                  onUpdate={(updates) => handleUpdateSection(selectedSection.id, updates)}
                  onClose={() => setSelectedSectionId(null)}
                />
              </div>
            )}
            
            {/* Backdrop for mobile when PropertyPanel is open */}
            {selectedSection && (
              <div 
                className="fixed inset-0 bg-black/50 z-40 lg:hidden"
                onClick={() => setSelectedSectionId(null)}
              />
            )}
          </>
        )}

        {/* Preview Mode */}
        {isPreviewMode && (
          <div className="flex-1 overflow-auto">
            <Canvas
              sections={sections}
              selectedSectionId={null}
              onSectionSelect={() => {}}
              onSectionDelete={() => {}}
              onSectionDuplicate={() => {}}
              previewMode={previewMode}
              isPreview={true}
            />
          </div>
        )}
      </div>

      {/* Inline CSS Editor */}
      {cssEditorSection && (
        <InlineCSSEditor
          sectionId={cssEditorSection.sectionId}
          type="section"
          onClose={() => setCssEditorSection(null)}
        />
      )}

      {/* Global CSS Editor */}
      {globalCSSEditor && (
        <InlineCSSEditor
          sectionId="global"
          type="global"
          onClose={() => setGlobalCSSEditor(false)}
        />
      )}

      {/* Page CSS Editor */}
      {pageCSSEditor && (
        <InlineCSSEditor
          sectionId={pageCSSEditor.pageId}
          type="page"
          onClose={() => setPageCSSEditor(null)}
        />
      )}

      {/* Global Media Browser */}
      <MediaBrowser
        isOpen={mediaBrowser.isOpen}
        onClose={() => setMediaBrowser(prev => ({ ...prev, isOpen: false }))}
        onSelect={(url) => {
          mediaBrowser.onSelect(url);
          setMediaBrowser(prev => ({ ...prev, isOpen: false }));
        }}
        acceptTypes={mediaBrowser.acceptTypes}
      />

      {/* Page JSON Editor */}
      {isJSONEditorOpen && (
        <PageJSONEditor
          sections={sections}
          onSave={handleJSONSave}
          onClose={() => setIsJSONEditorOpen(false)}
        />
      )}
    </div>
  );
}